  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;  // 1 assignment (6) + 1 binding (1) + 1 conditional (4) + 1 invocation (2) [*] + 1 constant (1) = 15
  const enchantmentSurcharge =
